How-To-Repeat: Run this program twice on a system that uses mfs as /tmp.

#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>

#define XSIZE   4096

main()
{
        char    *buf;
        int     fsok, memok;
        int     fd;

        fd = open("/tmp/suck.out", O_WRONLY|O_CREAT|O_TRUNC, 0644);
        if (fd == -1) {
                perror("open");
                exit(1);
        }

        fsok = memok = 1;
        while (fsok || memok) {
                if (memok) {
                        buf = malloc(XSIZE);
                        if (buf == NULL) {
                                perror("malloc");
                                memok = 0;
                        }
                }
                if (fsok) {
                        if (write(fd, buf, XSIZE) != XSIZE) {
                                perror("write");
                                fsok = 0;
                        }
                }
        }
        printf("sleeping...\n");
        sleep(500);
        return 0;
}
